import React from "react";
import { TextField, Box } from "@mui/material";
import parse from 'html-react-parser';
import DOMPurify from 'dompurify';
import FAWTypography from './FAWTypography';
import RequiredIndicator from './RequiredIndicator';
import { colors } from "../../utils/designTokens";

/** Resolve design token value (handles { value } objects from theme tokens). */
const resolveToken = (v) => (v != null && typeof v === 'object' && 'value' in v ? v.value : v);

// Generate unique ID if not provided
const generateUniqueId = () => {
    return `atlas-input-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
};

const parseHtmlContent = (htmlString) => {
    if (!htmlString) return '';

    if (React.isValidElement(htmlString)) {
        return htmlString;
    }

    if (typeof htmlString !== 'string') {
        if (htmlString && typeof htmlString === 'object') {
            if (Array.isArray(htmlString) || htmlString.$$typeof || htmlString.type) {
                return htmlString;
            }
        }
        return String(htmlString);
    }

    try {
        // Clean up the HTML string first
        let cleanHtml = htmlString;

        // Remove excessive spaces and clean up common patterns
        cleanHtml = cleanHtml.replace(/&nbsp;/g, ' ');
        cleanHtml = cleanHtml.replace(/\s+/g, ' ');
        cleanHtml = cleanHtml.trim();

        // If it looks like plain text, return it as-is
        if (!cleanHtml.includes('<') && !cleanHtml.includes('>')) {
            return cleanHtml;
        }

        const sanitizedHtml = DOMPurify.sanitize(cleanHtml, {
            ALLOWED_TAGS: ['br', 'span', 'strong', 'em', 'b', 'i', 'u', 'p', 'div'],
            ALLOWED_ATTR: ['style', 'class']
        });

        return parse(sanitizedHtml);
    } catch (error) {
        console.warn('Error parsing HTML content:', error);
        return htmlString;
    }
};

const FAWInput = React.memo(({ onChange, label, value, defaultValue, defaultText, placeholder, id, name, type, InputLabelProps, inputProps, error, helperText, multiline, rows, labelSx, endAdornment, required, fullWidth, sx, isDateField, ...rest }) => {
    // Generate unique ID if not provided
    const uniqueId = id || name || generateUniqueId();

    // Handle default text - use defaultText prop, then defaultValue, then placeholder as fallback
    const effectiveDefaultValue = defaultValue || defaultText || '';
    const effectivePlaceholder = placeholder || defaultText || '';

    // Support both controlled and uncontrolled usage
    // If value is provided, use controlled mode; otherwise use uncontrolled with defaultValue
    const handleChange = (e) => {
        if (typeof onChange === "string" && window[onChange]) {
            window[onChange](e);
        } else if (typeof onChange === "function") {
            onChange(e);
        }
    };

    // Determine if this is a controlled or uncontrolled component
    const isControlled = value !== undefined;

    // For date fields, override type to 'date' to get native date picker
    const effectiveType = isDateField ? 'date' : (type || 'text');

    return (
        <div style={rest.divSx}>
            {label && (
                <FAWTypography
                    variant="body2"
                    component="label"
                    htmlFor={uniqueId}
                    sx={{
                        display: "block",
                        marginBottom: "4px",
                        ...labelSx,
                    }}
                >
                    <Box component="span" sx={{ display: 'inline-flex', alignItems: 'baseline' }}>
                        {parseHtmlContent(label)}
                        <RequiredIndicator required={required} />
                    </Box>
                </FAWTypography>
            )}
            <TextField
                id={uniqueId}
                name={name || uniqueId}
                type={effectiveType}
                variant="outlined"
                fullWidth={fullWidth}
                {...(isControlled ? { value: value } : { defaultValue: effectiveDefaultValue })}
                placeholder={effectivePlaceholder}
                onChange={handleChange}
                InputLabelProps={{
                    ...InputLabelProps,
                    shrink: isDateField ? true : InputLabelProps?.shrink,
                }}
                inputProps={inputProps}
                multiline={multiline}
                rows={rows}
                error={!!error}
                helperText={helperText || error}
                FormHelperTextProps={{
                    sx: {
                        fontSize: '12px !important',
                        marginLeft: '0 !important',
                        marginTop: '4px !important',
                        '&.MuiFormHelperText-root': {
                            fontSize: '12px !important',
                        }
                    }
                }}
                InputProps={{
                    endAdornment: endAdornment,
                    ...rest.InputProps
                }}
                sx={(theme) => {
                    const tokens = theme?.tokens;
                    const input = tokens?.component?.input;
                    // Default: light gray border (original). Dark border only on hover.
                    const defaultBorderColor = colors.ui.border.static || '#DADADA';
                    const borderWidth = resolveToken(input?.outlined?.default?.border?.borderWidth) || '1px';
                    const borderStyle = resolveToken(input?.outlined?.default?.border?.borderStyle) || 'solid';
                    const outlinedRootStyles = {
                        background: resolveToken(input?.outlined?.default?.container?.background) || colors.background.default,
                        color: resolveToken(input?.outlined?.default?.container?.color) || colors.type.default,
                        borderRadius: '8px',
                        borderColor: defaultBorderColor,
                        borderWidth,
                        borderStyle,
                        // Border only on notched outline (MUI's visible border) to avoid double border with root.
                        '& .MuiOutlinedInput-notchedOutline': {
                            border: 'none',
                        },
                        '&:hover': {
                            background: resolveToken(input?.outlined?.hover?.container?.background) || colors.background.secondary,
                            borderColor: resolveToken(input?.outlined?.hover?.border?.borderColor) || colors.action.link.default,
                        },
                        '&.Mui-focused': {
                            background: resolveToken(input?.outlined?.active?.container?.background) || colors.background.default,
                            borderColor: defaultBorderColor,
                        },
                        '&.Mui-error': {
                            background: resolveToken(input?.outlined?.error?.container?.background) || (colors.status.error ? `${colors.status.error}15` : 'rgba(211, 47, 47, 0.08)'),
                            borderColor: resolveToken(input?.outlined?.error?.border?.borderColor) || colors.status.error,
                        },
                    };
                    return {
                        color: resolveToken(input?.outlined?.default?.container?.color) || colors.type.default,
                        '& .MuiOutlinedInput-root': outlinedRootStyles,
                        ...(isDateField && {
                            '& input[type="date"]': {
                                cursor: 'pointer',
                                '&::-webkit-calendar-picker-indicator': {
                                    cursor: 'pointer',
                                    opacity: 1,
                                    display: 'block',
                                    width: '20px',
                                    height: '20px',
                                    marginRight: '4px'
                                }
                            }
                        }),
                        // Enhanced placeholder styling
                        '& .MuiOutlinedInput-input::placeholder': {
                            color: colors.type.tertiary,
                            opacity: 1,
                            fontSize: '16px'
                        },
                        // Helper text styling
                        '& .MuiFormHelperText-root': {
                            fontSize: '12px !important',
                            marginLeft: '0 !important',
                            marginTop: '4px !important',
                        },
                        // Disabled state - show default cursor instead of text cursor
                        '& .Mui-disabled': {
                            cursor: 'default !important',
                        },
                        '& .Mui-disabled .MuiOutlinedInput-input': {
                            cursor: 'default !important',
                        },
                        ...sx
                    };
                }}
                {...rest}
            />
        </div>
    );
});

export default FAWInput; 