import React, { useEffect, useRef } from 'react';
import { CKEditor } from 'ckeditor4-react';
import { colors } from '../../utils/designTokens';

const DEFAULT_EDITOR_URL = '/Scripts/ckeditor/ckeditor.js';
const FAW_CSS_URL = '/Scripts/ckeditor/faw-ckeditor.css';

const FAWTextEditor = ({
  value,
  onChange,
  height = 250,
  readOnly = false,
  placeholder = '',
  editorUrl,
  scriptUrl,
  licenseKey,
  refDomains = []
}) => {
  const finalEditorUrl = editorUrl || scriptUrl || DEFAULT_EDITOR_URL;
  const editorRef = useRef(null);

  // Load FAW CSS for CKEditor styling
  useEffect(() => {
    const loadFAWCSS = () => {
      // Check if FAW CSS is already loaded
      const existingLink = document.querySelector('link[href*="faw-ckeditor.css"]');
      if (!existingLink) {
        const link = document.createElement('link');
        link.rel = 'stylesheet';
        link.type = 'text/css';
        link.href = FAW_CSS_URL;
        link.id = 'faw-ckeditor-css';
        document.head.appendChild(link);
      }
    };

    loadFAWCSS();
  }, []);

  // Ensure refCodeArray is available globally for CKEditor placeholder plugin
  useEffect(() => {
    // Always use refDomains prop if provided (allows filtering per question type)
    if (Array.isArray(refDomains) && refDomains.length > 0) {
      // Flatten RefCodes from all domains for placeholder dropdown
      const refCodeArray = [];
      refDomains.forEach(domain => {
        if (domain && domain.RefCodes && Array.isArray(domain.RefCodes) && domain.RefCodes.length > 0) {
          // If domain has RefCodes, add each RefCode
          domain.RefCodes.forEach(rc => {
            if (rc) {
              const refCodeName = `${rc.Code}`;
              const displayText = rc.Description;
              refCodeArray.push([refCodeName, displayText]);
            }
          });
        } else if (domain && domain.Name) {
          // Fallback: if no RefCodes, use domain name (for backward compatibility)
          refCodeArray.push([domain.Name, domain.Description || domain.Name]);
        }
      });
      window.refCodeArray = refCodeArray;
    }
  }, [refDomains]);




  // Cleanup when component unmounts
  useEffect(() => {
    return () => {
      if (editorRef.current) {
        try {
          editorRef.current.destroy();
        } catch (error) {
          console.warn('Error destroying CKEditor:', error);
        }
      }
    };
  }, []);

  const handleReady = (evt) => {
    editorRef.current = evt.editor;
    
    // Only set initial data if editor is empty and we have a value
    // This prevents interference with user typing
    if (value && evt.editor.getData() === '') {
      evt.editor.setData(value);
    }
  };

  const handleBeforeLoad = (CKEDITOR) => {
    // Ensure refCodeArray is available globally for CKEditor placeholder plugin
    // Always use refDomains prop if provided (allows filtering per question type)
    if (Array.isArray(refDomains) && refDomains.length > 0) {
      // Flatten RefCodes from all domains for placeholder dropdown
      const refCodeArray = [];
      refDomains.forEach(domain => {
        if (domain && domain.RefCodes && Array.isArray(domain.RefCodes) && domain.RefCodes.length > 0) {
          // If domain has RefCodes, add each RefCode
          domain.RefCodes.forEach(rc => {
            if (rc) {
              const refCodeName = `${domain.Name}.${rc.Code}`;
              const displayText = rc.Meaning || rc.Description || rc.Code || refCodeName;
              refCodeArray.push([refCodeName, displayText]);
            }
          });
        } else if (domain && domain.Name) {
          // Fallback: if no RefCodes, use domain name (for backward compatibility)
          refCodeArray.push([domain.Name, domain.Description || domain.Name]);
        }
      });
      window.refCodeArray = refCodeArray;
    }
    // If refDomains is not provided, use the current window.refCodeArray (read it fresh each time)
    // This ensures we get the value set by ControlSearch (for question editor) or CSHTML (for notification page)
    else {
      // Read current value - don't modify it
      // ControlSearch sets it to ["Company Name"] for question editor
      // Notification page CSHTML sets it for notification editor
      if (typeof window.refCodeArray === 'undefined') {
        window.refCodeArray = [];
      } 
    }
  };

  const handleChange = (evt) => {
    const newData = evt.editor.getData();
    
    if (onChange) {
      onChange(newData);
    } else {
      console.warn('FAWTextEditor: onChange prop is not provided');
    }
  };

  const handleError = (evt) => {
    console.error('CKEditor error:', evt);
  };

  return (
    <div style={{ width: '100%' }}>
      <CKEditor
        editorUrl={finalEditorUrl}
        initData={value || ''} // Try initData instead of data for older ckeditor4-react versions
        readOnly={readOnly}
        config={{
          height: height,
          placeholder: placeholder,
          // Prevent text direction issues
          contentsLangDirection: 'ltr',
          extraPlugins: 'placeholder,tooltip,anchortext,fawdialog',
          uiColor: colors.background.default || '#ffffff',
          // License key configuration
          ...(licenseKey ? { licenseKey } : 
              (window.CKEDITOR_LICENSE_KEY ? { licenseKey: window.CKEDITOR_LICENSE_KEY } : {}))
        }}
        onBeforeLoad={handleBeforeLoad}
        onInstanceReady={handleReady}
        onChange={handleChange}
        onError={handleError}
      />
    </div>
  );
};

export default FAWTextEditor;