import React from "react";
import { Box, FormLabel, FormControl, RadioGroup, FormControlLabel, Radio } from "@mui/material";
import RequiredIndicator from './RequiredIndicator';
import { colors } from "../../utils/designTokens";

const FAWRadioGroup = React.memo(({ id, options = [], value, defaultValue, onChange, label, row = false, sx, required, labelSx, ...rest }) => {
  const handleChange = typeof onChange === "string" ? window[onChange] : onChange;
  return (
    row ? (
      <Box display="flex" alignItems="center" width="100%" gap={2} sx={sx}>
        {label && (
          <FormLabel
            component="span"
            sx={{ flexBasis: '30%', width: '30%', minWidth: 0, fontWeight: 500, fontSize: '1rem' }}
          >
            {label}
          </FormLabel>
        )}
        <Box sx={{ flexBasis: '70%', width: '70%', minWidth: 0 }}>
          <RadioGroup id={id} value={value} defaultValue={defaultValue} onChange={handleChange} row={row} {...rest}>
            {options.map((option, idx) => (
              <FormControlLabel
                key={idx}
                value={option.value}
                control={<Radio />}
                label={option.label}
                sx={{
                  '& .MuiFormControlLabel-label': {
                    ...labelSx
                  }
                }}
              />
            ))}
          </RadioGroup>
        </Box>
      </Box>
    ) : (
      <Box sx={sx}>
        {label && (
          <FormLabel
            component="div"
            sx={{
              display: "block",
              marginBottom: 1,
              fontWeight: 500,
              fontSize: '16px',
              whiteSpace: 'normal',
              '& p': {
                display: 'inline',
                margin: 0,
                padding: 0,
              },
              '& div': {
                display: 'inline',
                margin: 0,
                padding: 0,
              }
            }}
          >
            <Box component="span" sx={{ display: 'inline-flex', alignItems: 'baseline' }}>
              {label}
              <RequiredIndicator required={required} />
            </Box>
          </FormLabel>
        )}
        <FormControl component="fieldset">
          <RadioGroup id={id} value={value} defaultValue={defaultValue} onChange={handleChange} row={row}>
            {options.map((option, idx) => (
              <FormControlLabel
                key={option.value ?? idx}
                value={option.value}
                control={
                  <Radio 
                    size={rest.size || 'medium'} 
                    sx={{'.MuiStack-root':{height: '16px', width: '16px'}}} 
                  />
                }
                label={option.label || null}
                sx={{
                  '& .MuiFormControlLabel-label': {
                    ...labelSx
                  }
                }}
              />
            ))}
          </RadioGroup>
        </FormControl>
      </Box>
    )
  );
});

export default FAWRadioGroup; 