import React from "react";
import FAWInput from "../../../../../component-widget/FAWInput";
import FAWCheckbox from "../../../../../component-widget/FAWCheckbox";
import FAWTextEditor from "../../../../../component-widget/FAWTextEditor";
import FAWTextarea from "../../../../../component-widget/FAWTextarea";
import FAWRadioGroup from "../../../../../component-widget/FAWRadioGroup";
import FAWTypography from "../../../../../component-widget/FAWTypography";
import EditorSection from "./EditorSection";

export default function BaseQuestionFields({ 
  item, 
  onChange, 
  disableText = false, 
  isDefaultLanguage = true,
  overrideHorizontalLineDisabled = null,
  suppressValidation = false,
  availableRefDomains = [],
  isDeployed = false,
  questionType = null
}) {
  // Centralized name validation pattern - used for both JS validation and HTML5 pattern attribute
  const NAME_PATTERN_REGEX = /^[A-Za-z][A-Za-z0-9_\-]*$/;
  const NAME_PATTERN_STRING = "^[A-Za-z][A-Za-z0-9_\\-]*$";
  
  const set = (k, v) => {
    onChange && onChange({ ...item, [k]: v });
  };
  const nameValue = item.name || "";
  const isNameValid = nameValue === "" || NAME_PATTERN_REGEX.test(nameValue);
  
  // Determine if name field should be disabled
  // Only allow name editing for LabelItemType questions
  const isLabelQuestion = questionType === "LabelItemType";
  const isNameFromRefCode = item._source && item._source.rc && nameValue && nameValue.trim() !== "";
  const isAddNewQuestion = item._source && item._source.rc && item._source.rc.Domain === "AddNewQuestion";
  const isCustomFields = item._source && item._source.rc && item._source.rc.Domain === "CustomFields";
  
  // Simple logic: disable name field if it's NOT a label question OR if version is deployed
  const isNameDisabled = !isLabelQuestion || isDeployed;
  
  // Determine if horizontal line should be disabled
  const isHorizontalLineDisabled = overrideHorizontalLineDisabled !== null 
    ? overrideHorizontalLineDisabled 
    : !isDefaultLanguage || isDeployed;

  // Legacy behavior: Don't pass refDomains prop - let FAWTextEditor use global window.refCodeArray
  // which is set to only ["Company Name"] for all question types in ControlSearch.jsx

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      {/* Name Field */}
      <FAWInput
        label="Name"
        value={nameValue}
        onChange={(e)=> set("name", e.target.value)}
        fullWidth
        inputProps={{ 
          pattern: NAME_PATTERN_STRING,
          maxLength: 30
        }}
        error={!isNameValid}
        helperText={!isNameValid ? "Names must begin with a letter and contain only letters, numbers, underscore or hyphen." : ""}
        disabled={isNameDisabled}
        required={true}
      />

      {/* Base Question Editor */}
      <FAWTextEditor value={item.text || ""} onChange={(v)=> set("text", v)} readOnly={disableText || isDeployed} />

      {/* Required Checkbox */}
      {suppressValidation === false && (
        <FAWCheckbox
          label="Required"
          checked={!!item.required}
          onChange={(e)=> set("required", e.target.checked)}
          disabled={!isDefaultLanguage || isDeployed}
        />
      )}

      {/* Validation Message */}
      {suppressValidation === false && (
        <div>
          <FAWTypography variant="body2" sx={{ marginBottom: 1, fontWeight: 500 }}>
            Validation Message
          </FAWTypography>
          <FAWTextarea
            label=""
            value={item.validationMessage || ""}
            onChange={(e)=> set("validationMessage", e.target.value)}
            disabled={!item.required || isDeployed}
            rows={3}
            required={item.required}
            error={item.required && (!item.validationMessage || item.validationMessage.trim() === "")}
            helperText={item.required && (!item.validationMessage || item.validationMessage.trim() === "") ? "Validation Message cannot be empty for required fields" : ""}
            fullWidth
            placeholder="Multi line text"
          />
        </div>
      )}

      {/* Horizontal Lines Above */}
      <div>
        <FAWTypography variant="body2" sx={{ marginBottom: 1, fontWeight: 600 }}>
          Horizontal Line Above
        </FAWTypography>
        <FAWRadioGroup
          label=""
          options={[{ label: "Yes", value: "true" }, { label: "No", value: "false" }]}
          value={(() => {
            const currentValue = item.horizontalLine === true || item.horizontalLine === "true" ? "true" : "false";
            return currentValue;
          })()}
          onChange={(event)=> {
            const val = event.target.value;
            set("horizontalLine", val === "true");
          }}
          disabled={isHorizontalLineDisabled}
          row={false}
          spacing={3}
        />
      </div>

      {/* Report Column Header */}
      <FAWInput
        label="Report Column Header"
        value={item.reportColumnHeader || ""}
        onChange={(e)=> set("reportColumnHeader", e.target.value)}
        fullWidth
        inputProps={{ maxLength: 50 }}
        helperText="This will be used as the column header in exported reports"
        disabled={isDeployed}
        placeholder="Enter column header for reports"
      />

    </div>
  );
}