import React from "react";
import TextField from "@mui/material/TextField";
import { Box } from "@mui/material";
import FAWTypography from './FAWTypography';
import RequiredIndicator from './RequiredIndicator';
import { colors } from "../../utils/designTokens";

const FAWTextarea = React.memo(({ onChange, label, value, defaultValue, id, name, rows = 4, disabled = false, className = '', style = {}, variant = 'outlined', required, sx, ...rest }) => {
  // Support both controlled and uncontrolled usage, like FAWInput
  const handleChange = (e) => {
    if (typeof onChange === "string" && window[onChange]) {
      window[onChange](e);
    } else if (typeof onChange === "function") {
      onChange(e);
    }
  };

  return (
    <div className={className} style={{ width: '100%', ...style }}>
      {label && (
        <FAWTypography 
          variant="body2" 
          component="label" 
          htmlFor={id}
          sx={{ 
            display: "block", 
            marginBottom: "4px", 
            fontWeight: "500",
            fontSize: "14px"
          }}
        >
          <Box component="span" sx={{ display: 'inline-flex', alignItems: 'baseline' }}>
            {label}
            <RequiredIndicator required={required} />
          </Box>
        </FAWTypography>
      )}
      <TextField
        id={id}
        name={name || id}
        variant={variant}
        value={value}
        defaultValue={defaultValue}
        onChange={handleChange}
        multiline
        minRows={rows}
        disabled={disabled}
        fullWidth
        sx={{
          '& .MuiOutlinedInput-input::placeholder': {
            color: colors.type.tertiary,
            opacity: 1,
            fontSize: '16px'
          },
          ...sx
        }}
        {...rest}
      />
    </div>
  );
});

export default FAWTextarea; 