import React, { useEffect } from "react";

export default function EditorShell({ children, onSave, saveRef }) {
  useEffect(() => {
    if (saveRef && onSave) {
      saveRef.current = onSave;
    }
    
    return () => {
      if (saveRef) {
        saveRef.current = null;
      }
    };
  }, [saveRef, onSave]);

  return (
    <div>
      {children}
    </div>
  );
}