import React from "react";
import { Box } from "@mui/material";
import FAWTypography from "../../../../../component-widget/FAWTypography";

export default function EditorSection({ title, children, sx }) {
  return (
    <Box component="section" sx={{ mb: 2, ...(sx || {}) }}>
      {title ? (
        <FAWTypography variant="subtitle2" sx={{ fontWeight: 600, mb: 1.5, mt: 1 }}>
          {title}
        </FAWTypography>
      ) : null}
      <Box>
        {children}
      </Box>
    </Box>
  );
}


